from collections import defaultdict
from typing import Tuple

def is_palindrome(s: str) -> bool:
    return s == s[::-1]

def find_distinct_palindromes(strings: Tuple[str, ...]) -> bool:
    counts = defaultdict(int)
    for s in strings:
        counts[s] += 1

    for s in strings:
        for i in range(1, len(s)):
            if is_palindrome(s[:i]) and is_palindrome(s[i:]):
                return True
            if is_palindrome(s[:i]) and is_palindrome(s[i+1:]):
                return True
            if is_palindrome(s[:i+1]) and is_palindrome(s[i:i+1]):
                return True

    return False

